    /**
     */
    private fun _parsePartwisePart(element: com.omnifret.gplayer.xml.XmlNode): Unit{
        var id: String? = element.attributes.get("id")
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(id)) || !this._idToTrackInfo.has(id!!))
        {
            return
        }
        var track: com.omnifret.gplayer.model.Track = this._idToTrackInfo.get(id!!)!!.track
        var index: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "measure" -> 
                {
                    this._parsePartwiseMeasure(c, track, index)
                    index++
                }
                else -> { }
            }
        }
        this._currentBarNumberDisplayPart = null
    }
    
    /**
     */
    private fun _parsePartwiseMeasure(element: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track, index: Double): Unit{
        var masterBar: com.omnifret.gplayer.model.MasterBar = this._getOrCreateMasterBar(element, index)
        var implicit: Boolean = element.attributes.get("implicit") == "yes"
        this._parsePartMeasure(element, masterBar, track, implicit, true)
        this._currentBarNumberDisplayBar = null
    }
    
    /**
     */
    private fun _parseTimewiseMeasure(element: com.omnifret.gplayer.xml.XmlNode, index: Double): Unit{
        var masterBar: com.omnifret.gplayer.model.MasterBar = this._getOrCreateMasterBar(element, index)
        var implicit: Boolean = element.attributes.get("implicit") == "yes"
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "part" -> 
                {
                    this._parseTimewisePart(c, masterBar, implicit)
                    this._currentBarNumberDisplayPart = null
                }
                "print" -> 
                {
                    this._parsePrint(c, masterBar, null, true)
                }
                else -> { }
            }
        }
        this._currentBarNumberDisplayBar = null
    }
    
    /**
     */
    private fun _getOrCreateMasterBar(element: com.omnifret.gplayer.xml.XmlNode, index: Double): com.omnifret.gplayer.model.MasterBar{
        var implicit: Boolean = element.attributes.get("implicit") == "yes"
        while (this._score.masterBars.length <= index)
        {
            var newMasterBar: com.omnifret.gplayer.model.MasterBar = com.omnifret.gplayer.model.MasterBar()
            if (implicit)
            {
                newMasterBar.isAnacrusis = true
            }
            this._score.addMasterBar(newMasterBar)
            if (newMasterBar.index > 0)
            {
                newMasterBar.timeSignatureDenominator = newMasterBar.previousMasterBar!!.timeSignatureDenominator
                newMasterBar.timeSignatureNumerator = newMasterBar.previousMasterBar!!.timeSignatureNumerator
                newMasterBar.tripletFeel = newMasterBar.previousMasterBar!!.tripletFeel
            }
        }
        var masterBar: com.omnifret.gplayer.model.MasterBar = this._score.masterBars[(index).toInt()]
        return masterBar
    }
    
    /**
     */
    private fun _parseTimewisePart(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, implicit: Boolean): Unit{
        var id: String? = element.attributes.get("id")
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(id)) || !this._idToTrackInfo.has(id!!))
        {
            return
        }
        var track: com.omnifret.gplayer.model.Track = this._idToTrackInfo.get(id!!)!!.track
        this._parsePartMeasure(element, masterBar, track, implicit, false)
    }
    
    /**
     * The current musical position within the bar.
     */
    private var _musicalPosition: Double = 0.0
    
    /**
     * The last known beat which was parsed. Might be used
     * to access the current voice/staff (e.g. on rests when we don't have notes)
     */
