    /**
     */
    private fun _parsePartMeasure(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track, implicit: Boolean, isPartwise: Boolean): Unit{
        this._musicalPosition = 0.0
        this._lastBeat = null
        masterBar.alternateEndings = this._nextMasterBarRepeatEnding
        var barLines: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode>(
        )
        
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "note" -> 
                {
                    this._parseNote(c, masterBar, track)
                }
                "backup" -> 
                {
                    this._parseBackup(c)
                }
                "forward" -> 
                {
                    this._parseForward(c)
                }
                "direction" -> 
                {
                    this._parseDirection(c, masterBar, track)
                }
                "attributes" -> 
                {
                    this._parseAttributes(c, masterBar, track)
                }
                "harmony" -> 
                {
                    this._parseHarmony(c, track)
                }
                "print" -> 
                {
                    this._parsePrint(c, masterBar, track, true)
                }
                "sound" -> 
                {
                    this._parseSound(c, masterBar, track)
                }
                "barline" -> 
                {
                    barLines.push(c)
                }
                else -> { }
            }
        }
        for (barLine in barLines)
        {
            this._parseBarLine(barLine, masterBar, track)
        }
        this._applySimileMarks(masterBar, track)
        var staff: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, 0.0)
        var bar: com.omnifret.gplayer.model.Bar = this._getOrCreateBar(staff, masterBar)
        if (implicit)
        {
            bar.barNumberDisplay = com.omnifret.gplayer.model.BarNumberDisplay.Hide
        }
        else if (isPartwise)
        {
            bar.barNumberDisplay = this._currentBarNumberDisplayBar ?: this._currentBarNumberDisplayPart
        }
        else 
        {
            bar.barNumberDisplay = this._currentBarNumberDisplayPart ?: this._currentBarNumberDisplayBar
        }
        this._keyAllStaves = null
    }
    
    /**
     */
    private fun _parsePrint(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track?, isMeasurePrint: Boolean): Unit{
        if (track != null)
        {
            if (element.getAttribute("new-system", "no") == "yes")
            {
                track!!.addLineBreaks(masterBar.index)
            }
            else if (element.getAttribute("new-page", "no") == "yes")
            {
                track!!.addLineBreaks(masterBar.index)
            }
        }
        var newDisplay: com.omnifret.gplayer.model.BarNumberDisplay? = null
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "measure-numbering" -> 
                {
                    when (c.innerText)
                    {
                        "none" -> 
                        {
                            newDisplay = com.omnifret.gplayer.model.BarNumberDisplay.Hide
                        }
                        "measure" -> 
                        {
                            newDisplay = com.omnifret.gplayer.model.BarNumberDisplay.AllBars
                        }
                        "system" -> 
                        {
                            newDisplay = com.omnifret.gplayer.model.BarNumberDisplay.FirstOfSystem
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
        if (isMeasurePrint)
        {
            this._currentBarNumberDisplayBar = newDisplay
        }
        else 
        {
            this._currentBarNumberDisplayPart = newDisplay
        }
    }
    
    /**
     */
    private fun _applySimileMarks(masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        if (this._simileMarkAllStaves != null)
        {
            for (s in track.staves)
            {
                var bar: com.omnifret.gplayer.model.Bar = this._getOrCreateBar(s, masterBar)
                bar.simileMark = this._simileMarkAllStaves!!
                if (bar.simileMark != com.omnifret.gplayer.model.SimileMark.None)
                {
                    this._clearBar(bar)
                }
            }
            if (this._simileMarkAllStaves!! == com.omnifret.gplayer.model.SimileMark.FirstOfDouble)
            {
                this._simileMarkAllStaves = com.omnifret.gplayer.model.SimileMark.SecondOfDouble
            }
            else 
            {
                this._simileMarkAllStaves = null
            }
        }
        if (this._simileMarkPerStaff != null)
        {
            var keys: com.omnifret.gplayer.collections.DoubleList = com.omnifret.gplayer.core.ecmaScript.Array.from(this._simileMarkPerStaff!!.keys())
            for (i in keys)
            {
                var s: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, i)
                var bar: com.omnifret.gplayer.model.Bar = this._getOrCreateBar(s, masterBar)
                bar.simileMark = this._simileMarkPerStaff!!.get(i)!!
                if (bar.simileMark != com.omnifret.gplayer.model.SimileMark.None)
                {
                    this._clearBar(bar)
                }
                if (bar.simileMark == com.omnifret.gplayer.model.SimileMark.FirstOfDouble)
                {
                    this._simileMarkPerStaff!!.set(i, com.omnifret.gplayer.model.SimileMark.SecondOfDouble)
                }
                else 
                {
                    this._simileMarkPerStaff!!.delete(i)
                }
            }
            if (this._simileMarkPerStaff!!.size == 0.0)
            {
                this._simileMarkPerStaff = null
            }
        }
    }
    
    /**
     */
    private fun _clearBar(bar: com.omnifret.gplayer.model.Bar): Unit{
        for (v in bar.voices)
        {
            var emptyBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
            emptyBeat.isEmpty = true
            v.addBeat(emptyBeat)
        }
    }
    
    /**
     */
    private fun _parseBarLine(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        for (c in element.childElements())
        {
