            }
        }
    }
    
    /**
     */
    private fun _parseRepeat(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var direction: String = element.getAttribute("direction")
        var times: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.getAttribute("times"), 10.0)
        if (times < 0 || com.omnifret.gplayer.core.ecmaScript.Number.isNaN(times))
        {
            times = 2.0
        }
        if (direction == "backward")
        {
            masterBar.repeatCount = times
        }
        else if (direction == "forward")
        {
            masterBar.isRepeatStart = true
        }
    }
    
    private var _nextMasterBarRepeatEnding: Double = 0.0
    
    /**
     */
    private fun _parseEnding(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var numbers: com.omnifret.gplayer.collections.DoubleList = element.getAttribute("number").splitBy(",").map(fun(v: String): Double{
            return com.omnifret.gplayer.core.ecmaScript.Number.parseInt(v, 10.0)
        }
        )
        var flags: Double = 0.0
        for (num in numbers)
        {
            flags = ((flags).toInt() or ((1 shl ((num - (1.0).toDouble())).toInt()) and 255)).toDouble()
        }
        masterBar.alternateEndings = flags
        when (element.getAttribute("type", ""))
        {
            "start" -> 
            {
                this._nextMasterBarRepeatEnding = ((this._nextMasterBarRepeatEnding).toInt() or (flags).toInt()).toDouble()
            }
            "stop", "discontinue" -> 
            {
                this._nextMasterBarRepeatEnding = ((this._nextMasterBarRepeatEnding).toInt() and (((flags).toInt()).toInt().inv()).toInt()).toDouble()
            }
            "continue" -> 
            {
            }
            else -> { }
        }
    }
    
