    /**
     */
    private fun _parseSound(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, _track: com.omnifret.gplayer.model.Track): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "midi-instrument" -> 
                {
                    this._parseSoundMidiInstrument(c, masterBar)
                }
                "swing" -> 
                {
                    this._parseSwing(c, masterBar)
                }
                "offset" -> 
                {
                }
                else -> { }
            }
        }
        if (element.attributes.has("coda"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.TargetCoda)
        }
        if (element.attributes.has("tocoda"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.JumpDaCoda)
        }
        if (element.attributes.has("dacapo"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.JumpDaCapo)
        }
        if (element.attributes.has("dalsegno"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.JumpDalSegno)
        }
        if (element.attributes.has("fine"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.TargetFine)
        }
        if (element.attributes.has("segno"))
        {
            masterBar.addDirection(com.omnifret.gplayer.model.Direction.TargetSegno)
        }
        if (element.attributes.has("pan"))
        {
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._nextBeatAutomations)))
            {
                this._nextBeatAutomations = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Automation>(
                )
                
            }
            var automation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
            automation.type = com.omnifret.gplayer.model.AutomationType.Balance
            automation.value = com.omnifret.gplayer.importer.MusicXmlImporter._interpolatePan(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(element.attributes.get("pan")!!))
            this._nextBeatAutomations!!.push(automation)
        }
        if (element.attributes.has("tempo"))
        {
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._nextBeatAutomations)))
            {
                this._nextBeatAutomations = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Automation>(
                )
                
            }
            var automation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
            automation.type = com.omnifret.gplayer.model.AutomationType.Tempo
            automation.value = com.omnifret.gplayer.importer.MusicXmlImporter._interpolatePercent(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(element.attributes.get("tempo")!!))
            this._nextBeatAutomations!!.push(automation)
        }
    }
    
    /**
     */
    private fun _parseSwing(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var first: Double = 0.0
        var second: Double = 0.0
        var swingType: com.omnifret.gplayer.model.Duration? = null
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "straight" -> 
                {
                    masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.NoTripletFeel
                    return
                }
                "first" -> 
                {
                    first = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                "second" -> 
                {
                    second = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                "swing-type" -> 
                {
                    swingType = this._parseBeatDuration(c)
                }
                else -> { }
            }
        }
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(swingType)))
        {
            swingType = com.omnifret.gplayer.model.Duration.Eighth
        }
        if (swingType!! == com.omnifret.gplayer.model.Duration.Eighth)
        {
            if (first == 2.0 && second == 1.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Triplet8th
            }
            else if (first == 3.0 && second == 1.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Dotted8th
            }
            else if (first == 1.0 && second == 3.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Scottish8th
            }
        }
        else if (swingType == com.omnifret.gplayer.model.Duration.Sixteenth)
        {
            if (first == 2.0 && second == 1.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Triplet16th
            }
            else if (first == 3.0 && second == 1.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Dotted16th
            }
            else if (first == 1.0 && second == 3.0)
            {
                masterBar.tripletFeel = com.omnifret.gplayer.model.TripletFeel.Scottish16th
            }
        }
    }
    
