                "pan" -> 
                {
                    if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._nextBeatAutomations)))
                    {
                        this._nextBeatAutomations = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Automation>(
                        )
                        
                    }
                    automation = com.omnifret.gplayer.model.Automation()
                    automation.type = com.omnifret.gplayer.model.AutomationType.Balance
                    automation.value = com.omnifret.gplayer.importer.MusicXmlImporter._interpolatePan(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText))
                    this._nextBeatAutomations!!.push(automation)
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseHarmony(element: com.omnifret.gplayer.xml.XmlNode, _track: com.omnifret.gplayer.model.Track): Unit{
        var chord: com.omnifret.gplayer.model.Chord = com.omnifret.gplayer.model.Chord()
        var degreeParenthesis: Boolean = false
        var degree: String = ""
        for (childNode in element.childElements())
        {
            when (childNode.localName)
            {
                "root" -> 
                {
                    chord.name = this._parseHarmonyRoot(childNode)
                }
                "kind" -> 
                {
                    chord.name = chord.name + this._parseHarmonyKind(childNode)
                    if (childNode.getAttribute("parentheses-degrees", "no") == "yes")
                    {
                        degreeParenthesis = true
                    }
                }
                "frame" -> 
                {
                    this._parseHarmonyFrame(childNode, chord)
                }
                "degree" -> 
                {
                    degree += this._parseDegree(childNode)
                }
                else -> { }
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(degree)))
        {
            chord.name += if(degreeParenthesis)  """(${(degree).toTemplate()})""" else degree
        }
        if (element.getAttribute("print-frame", "no") == "yes")
        {
            chord.showDiagram = true
            this._score.stylesheet.globalDisplayChordDiagramsInScore = true
        }
        if (element.getAttribute("print-object", "yes") == "yes")
        {
            chord.showDiagram = true
        }
        if (this._nextBeatChord == null)
        {
            this._nextBeatChord = chord
        }
    }
    
    /**
     */
    private fun _parseDegree(element: com.omnifret.gplayer.xml.XmlNode): String{
        var value: String = ""
        var alter: String = ""
        var type: String = ""
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "degree-value" -> 
                {
                    value = c.innerText
                }
                "degree-alter" -> 
                {
                    when (c.innerText)
                    {
                        "-1" -> 
                        {
                            alter = "♭"
                        }
                        "1" -> 
                        {
                            alter = "♯"
                        }
                        else -> { }
                    }
                }
                "degree-type" -> 
                {
                    type += c.getAttribute("text", "")
                }
                else -> { }
            }
        }
        return """${(type).toTemplate()}${(alter).toTemplate()}${(value).toTemplate()}"""
    }
    
    /**
     */
    private fun _parseHarmonyRoot(element: com.omnifret.gplayer.xml.XmlNode): String{
        var rootStep: String = ""
        var rootAlter: String = ""
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "root-step" -> 
                {
                    rootStep = c.innerText
                }
                "root-alter" -> 
                {
                    when (com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText))
                    {
                        -2.0 -> 
                        {
                            rootAlter = "bb"
                        }
                        -1.0 -> 
                        {
                            rootAlter = "b"
                        }
                        0.0 -> 
                        {
                            rootAlter = ""
                        }
                        1.0 -> 
                        {
                            rootAlter = "#"
                        }
                        2.0 -> 
                        {
                            rootAlter = "##"
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
        return rootStep + rootAlter
    }
    
