    /**
     */
    private fun _parseHarmonyFrame(xmlNode: com.omnifret.gplayer.xml.XmlNode, chord: com.omnifret.gplayer.model.Chord): Unit{
        for (frameChild in xmlNode.childElements())
        {
            when (frameChild.localName)
            {
                "frame-strings" -> 
                {
                    var stringsCount: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(frameChild.innerText, 10.0)
                    chord.strings = com.omnifret.gplayer.collections.DoubleList((stringsCount).toInt())
                    if (true) {
                        var i: Double = 0.0
                        
                        while(i < stringsCount){
                            chord.strings[(i).toInt()] = -1.0
                            i++
                        }
                    }
                }
                "first-fret" -> 
                {
                    chord.firstFret = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(frameChild.innerText, 10.0)
                }
                "frame-note" -> 
                {
                    var stringNo: Double? = null
                    var fretNo: Double? = null
                    for (noteChild in frameChild.childElements())
                    {
                        when (noteChild.localName)
                        {
                            "string" -> 
                            {
                                stringNo = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(noteChild.innerText, 10.0)
                            }
                            "fret" -> 
                            {
                                fretNo = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(noteChild.innerText, 10.0)
                                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(stringNo)) && fretNo!! >= 0))
                                {
                                    chord.strings[(stringNo!! - (1.0).toDouble()).toInt()] = fretNo!!
                                }
                            }
                            "barre" -> 
                            {
                                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(stringNo)) && com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(fretNo))) && noteChild.getAttribute("type") == "start"))
                                {
                                    chord.barreFrets.push(fretNo!!)
                                }
                            }
                            else -> { }
                        }
                    }
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseAttributes(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        var staffIndex: Double
        var staff: com.omnifret.gplayer.model.Staff
        var bar: com.omnifret.gplayer.model.Bar
        if (this._lastBeat == null)
        {
            for (c in element.childElements())
            {
                when (c.localName)
                {
                    "divisions" -> 
                    {
                        this._divisionsPerQuarterNote = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                    }
                    "key" -> 
                    {
                        this._parseKey(c, masterBar, track)
                    }
                    "time" -> 
                    {
                        this._parseTime(c, masterBar)
                    }
                    "staves" -> 
                    {
                        track.ensureStaveCount(com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0))
                    }
                    "clef" -> 
                    {
                        staffIndex = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.getAttribute("number", "1"), 10.0) - (1.0).toDouble()
                        staff = this._getOrCreateStaff(track, staffIndex)
                        bar = this._getOrCreateBar(staff, masterBar)
                        this._parseClef(c, bar)
                    }
                    "staff-details" -> 
                    {
                        staffIndex = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.getAttribute("number", "1"), 10.0) - (1.0).toDouble()
                        staff = this._getOrCreateStaff(track, staffIndex)
                        this._parseStaffDetails(c, staff)
                    }
                    "transpose" -> 
                    {
                        this._parseTranspose(c, track)
                    }
                    "measure-style" -> 
                    {
                        this._parseMeasureStyle(c, track, false)
                    }
                    else -> { }
                }
            }
        }
        else 
        {
            for (c in element.childElements())
            {
                when (c.localName)
                {
                    "divisions" -> 
                    {
                        this._divisionsPerQuarterNote = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                    }
                    "measure-style" -> 
                    {
                        this._parseMeasureStyle(c, track, true)
                    }
                    else -> { }
                }
            }
        }
    }
    
    private var _simileMarkAllStaves: com.omnifret.gplayer.model.SimileMark? = null
    
    private var _simileMarkPerStaff: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.model.SimileMark>? = null
    
    private var _isBeatSlash: Boolean = false
    
    /**
     */
    private fun _parseMeasureStyle(element: com.omnifret.gplayer.xml.XmlNode, _track: com.omnifret.gplayer.model.Track, midBar: Boolean): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "measure-repeat" -> 
                {
                    if (!midBar)
                    {
                        var simileMark: com.omnifret.gplayer.model.SimileMark? = null
                        when (c.getAttribute("type"))
                        {
                            "start" -> 
                            {
                                when (com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.getAttribute("slashes", "1"), 10.0))
                                {
                                    1.0 -> 
                                    {
                                        simileMark = com.omnifret.gplayer.model.SimileMark.Simple
                                    }
                                    2.0 -> 
                                    {
                                        simileMark = com.omnifret.gplayer.model.SimileMark.FirstOfDouble
                                    }
                                    else -> 
                                    {
                                    }
                                }
                            }
                            "stop" -> 
                            {
                                simileMark = null
                            }
                            else -> { }
                        }
                        if (element.attributes.has("number"))
                        {
                            this._simileMarkPerStaff = this._simileMarkPerStaff ?: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.model.SimileMark>()
                            var staff: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.attributes.get("number")!!, 10.0) - (1.0).toDouble()
                            if (simileMark == null)
                            {
                                this._simileMarkPerStaff!!.delete(staff)
                            }
                            else 
                            {
                                this._simileMarkPerStaff!!.set(staff, simileMark!!)
                            }
                        }
                        else 
                        {
                            this._simileMarkAllStaves = simileMark
                        }
                    }
                }
                "slash" -> 
                {
                    when (c.getAttribute("type"))
                    {
                        "start" -> 
                        {
                            this._isBeatSlash = true
                        }
                        "stop" -> 
                        {
                            this._isBeatSlash = false
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseTranspose(element: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var semitones: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "chromatic" -> 
                {
                    semitones += com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                }
                "octave-change" -> 
                {
                    semitones += com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText) * (12.0).toDouble()
                }
                else -> { }
            }
        }
        if (element.attributes.has("number"))
        {
            var staff: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.attributes.get("number")!!, 10.0) - (1.0).toDouble())
            this._getStaffContext(staff).transpose = semitones
            staff.displayTranspositionPitch = semitones
        }
        else 
        {
            for (staff in track.staves)
            {
                this._getStaffContext(staff).transpose = semitones
                staff.displayTranspositionPitch = semitones
            }
        }
    }
    
    /**
     */
    private fun _parseStaffDetails(element: com.omnifret.gplayer.xml.XmlNode, staff: com.omnifret.gplayer.model.Staff): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "staff-lines" -> 
                {
                    staff.standardNotationLineCount = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                "staff-tuning" -> 
                {
                    this._parseStaffTuning(c, staff)
                }
                "capo" -> 
                {
                    staff.capo = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseStaffTuning(element: com.omnifret.gplayer.xml.XmlNode, staff: com.omnifret.gplayer.model.Staff): Unit{
        if (staff.stringTuning.tunings.length == 0.0)
        {
            staff.showTablature = true
            staff.showStandardNotation = false
            staff.stringTuning.tunings = com.omnifret.gplayer.collections.DoubleList((staff.standardNotationLineCount).toInt()).fill(0.0)
        }
        var line: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.getAttribute("line"), 10.0)
        var tuningStep: String = "C"
        var tuningOctave: String = ""
        var tuningAlter: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "tuning-step" -> 
                {
                    tuningStep = c.innerText
                }
                "tuning-alter" -> 
                {
                    tuningAlter = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                }
                "tuning-octave" -> 
                {
                    tuningOctave = c.innerText
                }
                else -> { }
            }
        }
        var tuning: Double = com.omnifret.gplayer.model.ModelUtils.getTuningForText(tuningStep + tuningOctave) + tuningAlter
        staff.tuning[(staff.tuning.length - line).toInt()] = tuning
    }
    
    /**
     */
    private fun _parseClef(element: com.omnifret.gplayer.xml.XmlNode, bar: com.omnifret.gplayer.model.Bar): Unit{
        var sign: String = "s"
        var line: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "sign" -> 
                {
                    sign = c.innerText.lowercase()
                }
                "line" -> 
                {
                    line = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                "clef-octave-change" -> 
                {
                    when (com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0))
                    {
                        -2.0 -> 
                        {
                            bar.clefOttava = com.omnifret.gplayer.model.Ottavia._15mb
                        }
                        -1.0 -> 
                        {
                            bar.clefOttava = com.omnifret.gplayer.model.Ottavia._8vb
                        }
                        1.0 -> 
                        {
                            bar.clefOttava = com.omnifret.gplayer.model.Ottavia._8va
                        }
                        2.0 -> 
                        {
                            bar.clefOttava = com.omnifret.gplayer.model.Ottavia._15mb
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
        when (sign)
        {
            "g" -> 
            {
                bar.clef = com.omnifret.gplayer.model.Clef.G2
            }
            "f" -> 
            {
                bar.clef = com.omnifret.gplayer.model.Clef.F4
            }
            "c" -> 
            {
                if (line == 3.0)
                {
                    bar.clef = com.omnifret.gplayer.model.Clef.C3
                }
                else 
                {
                    bar.clef = com.omnifret.gplayer.model.Clef.C4
                }
            }
            "percussion" -> 
            {
                bar.clef = com.omnifret.gplayer.model.Clef.Neutral
                bar.staff.isPercussion = true
            }
            "tab" -> 
            {
                bar.clef = com.omnifret.gplayer.model.Clef.G2
                bar.staff.showTablature = true
            }
            else -> 
            {
                bar.clef = com.omnifret.gplayer.model.Clef.G2
            }
        }
    }
    
    /**
     */
    private fun _parseTime(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var beatsParsed: Boolean = false
        var beatTypeParsed: Boolean = false
        for (c in element.childElements())
        {
            var v: String = c.innerText
            when (c.localName)
            {
                "beats" -> 
                {
                    if (!beatsParsed)
                    {
                        if (v.indexOfInDouble("+") == -1.0)
                        {
                            masterBar.timeSignatureNumerator = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(v, 10.0)
                        }
                        else 
                        {
                            masterBar.timeSignatureNumerator = v.splitBy("+").map(fun(v: String): Double{
                                return com.omnifret.gplayer.core.ecmaScript.Number.parseInt(v, 10.0)
                            }
                            ).reduce(fun(sum: Double, v: Double): Double{
                                return v + sum
                            }
                            , 0.0)
                        }
                        beatsParsed = true
                    }
                }
                "beat-type" -> 
                {
                    if (!beatTypeParsed)
                    {
                        if (v.indexOfInDouble("+") == -1.0)
                        {
                            masterBar.timeSignatureDenominator = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(v, 10.0)
                        }
                        else 
                        {
                            masterBar.timeSignatureDenominator = v.splitBy("+").map(fun(v: String): Double{
                                return com.omnifret.gplayer.core.ecmaScript.Number.parseInt(v, 10.0)
                            }
                            ).reduce(fun(sum: Double, v: Double): Double{
                                return v + sum
                            }
                            , 0.0)
                        }
                        beatTypeParsed = true
                    }
                }
                else -> { }
            }
        }
        when (element.getAttribute("symbol", ""))
        {
            "common", "cut" -> 
            {
                masterBar.timeSignatureCommon = true
            }
            else -> { }
        }
    }
    
    private var _keyAllStaves: com.omnifret.gplayer.core.IArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>? = null
    
    /**
     */
    private fun _parseKey(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        var fifths: Double = -(com.omnifret.gplayer.model.KeySignature.C.toDouble())
        var mode: String = ""
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "fifths" -> 
                {
                    fifths = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                }
                "mode" -> 
                {
                    mode = c.innerText
                }
                else -> { }
            }
        }
        var keySignature: com.omnifret.gplayer.model.KeySignature
        if (-7.0 <= fifths && fifths <= 7)
        {
            keySignature = com.omnifret.gplayer.model.KeySignature.fromValue(fifths)
        }
        else 
        {
            keySignature = com.omnifret.gplayer.model.KeySignature.C
        }
        var keySignatureType: com.omnifret.gplayer.model.KeySignatureType
        if (mode == "minor")
        {
            keySignatureType = com.omnifret.gplayer.model.KeySignatureType.Minor
        }
        else 
        {
            keySignatureType = com.omnifret.gplayer.model.KeySignatureType.Major
        }
        if (element.attributes.has("number"))
        {
            var staff: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.attributes.get("number")!!, 10.0) - (1.0).toDouble())
            var bar: com.omnifret.gplayer.model.Bar = this._getOrCreateBar(staff, masterBar)
            bar.keySignature = keySignature
            bar.keySignatureType = keySignatureType
        }
        else 
        {
            this._keyAllStaves = com.omnifret.gplayer.core.ArrayTuple<com.omnifret.gplayer.model.KeySignature, com.omnifret.gplayer.model.KeySignatureType>(keySignature, keySignatureType)
            for (s in track.staves)
            {
                if (s.bars.length > masterBar.index)
                {
                    s.bars[(masterBar.index).toInt()].keySignature = keySignature
                    s.bars[(masterBar.index).toInt()].keySignatureType = keySignatureType
                }
            }
        }
    }
    
    /**
     */
    private fun _parseDirection(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        var directionTypes: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode>(
        )
        
        var offset: Double? = null
        var staffIndex: Double = -1.0
        var tempo: Double = -1.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "direction-type" -> 
                {
                    var type: com.omnifret.gplayer.xml.XmlNode? = c.firstElement
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(type)))
                    {
                        directionTypes.push(type!!)
                    }
                }
                "offset" -> 
                {
                    offset = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                }
                "voice" -> 
                {
                }
                "staff" -> 
                {
                    staffIndex = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0) - (1.0).toDouble()
                }
                "sound" -> 
                {
                    if (c.attributes.has("tempo"))
                    {
                        tempo = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.attributes.get("tempo")!!)
                    }
                }
                else -> { }
            }
        }
        var staff: com.omnifret.gplayer.model.Staff? = null
        if (staffIndex >= 0)
        {
            staff = this._getOrCreateStaff(track, staffIndex)
        }
        else if (this._lastBeat != null)
        {
            staff = this._lastBeat!!.voice.bar.staff
        }
        else 
        {
            staff = this._getOrCreateStaff(track, 0.0)
        }
        var bar: com.omnifret.gplayer.model.Bar? = if(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(staff!!)))  this._getOrCreateBar(staff!!, masterBar) else null
        var getRatioPosition: (() -> Double) = fun(): Double{
            var timelyPosition: Double = this._musicalPosition
            if (offset != null)
            {
                timelyPosition += offset!!
            }
            var totalDuration: Double = masterBar.calculateDuration(false)
            return timelyPosition / totalDuration
        }
        
        if (tempo > 0)
        {
            var tempoAutomation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
            tempoAutomation.type = com.omnifret.gplayer.model.AutomationType.Tempo
            tempoAutomation.value = tempo
            tempoAutomation.ratioPosition = getRatioPosition()
            if (!this._hasSameTempo(masterBar, tempoAutomation))
            {
                masterBar.tempoAutomations.push(tempoAutomation)
            }
        }
        var previousWords: String = ""
        for (direction in directionTypes)
        {
            when (direction.localName)
            {
                "rehearsal" -> 
                {
                    masterBar.section = com.omnifret.gplayer.model.Section()
                    masterBar.section!!.marker = direction.innerText
                }
                "segno" -> 
                {
                    masterBar.addDirection(com.omnifret.gplayer.model.Direction.TargetSegno)
                }
                "coda" -> 
                {
                    masterBar.addDirection(com.omnifret.gplayer.model.Direction.TargetCoda)
                }
                "words" -> 
                {
                    previousWords = direction.innerText
                }
                "wedge" -> 
                {
                    when (direction.getAttribute("type"))
                    {
                        "crescendo" -> 
                        {
                            this._nextBeatCrescendo = com.omnifret.gplayer.model.CrescendoType.Crescendo
                        }
                        "diminuendo" -> 
                        {
                            this._nextBeatCrescendo = com.omnifret.gplayer.model.CrescendoType.Decrescendo
                        }
                        "stop" -> 
                        {
                            this._nextBeatCrescendo = null
                        }
                        else -> { }
                    }
                }
                "dynamics" -> 
                {
                    var newDynamics: com.omnifret.gplayer.model.DynamicValue? = this._parseDynamics(direction)
                    if (newDynamics != null)
                    {
                        this._currentDynamics = ((newDynamics as com.omnifret.gplayer.model.DynamicValue))
                        this._score.stylesheet.hideDynamics = false
                    }
                }
                "dashes" -> 
                {
                    var type: String = direction.getAttribute("type", "start")
                    when (previousWords)
                    {
                        "LetRing" -> 
                        {
                            this._nextBeatLetRing = type == "start" || type == "continue"
                        }
                        "P.M." -> 
                        {
                            this._nextBeatPalmMute = type == "start" || type == "continue"
                        }
                        else -> { }
                    }
                    previousWords = ""
                }
                "pedal" -> 
                {
                    var pedal: com.omnifret.gplayer.model.SustainPedalMarker? = this._parsePedal(direction)
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(pedal)) && com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bar))))
                    {
                        pedal!!.ratioPosition = getRatioPosition()
                        var canHaveUp: Boolean = bar!!.sustainPedals.length > 0 && bar!!.sustainPedals[(bar!!.sustainPedals.length - (1.0).toDouble()).toInt()].pedalType != com.omnifret.gplayer.model.SustainPedalMarkerType.Up
                        if (pedal!!.pedalType != com.omnifret.gplayer.model.SustainPedalMarkerType.Up || canHaveUp)
                        {
                            bar!!.sustainPedals.push(pedal!!)
                        }
                    }
                }
                "metronome" -> 
                {
                    this._parseMetronome(direction, masterBar, getRatioPosition())
                }
                "octave-shift" -> 
                {
                    this._nextBeatOttavia = this._parseOctaveShift(direction)
                }
                else -> { }
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(previousWords)))
        {
            this._nextBeatText = previousWords
        }
    }
    
    /**
     */
    private fun _parseOctaveShift(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.Ottavia?{
        var type: String = element.getAttribute("type")
        var size: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(element.getAttribute("size", "8"), 10.0)
        when (size)
        {
            15.0 -> 
            {
                when (type)
                {
                    "up" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia._15mb
                    }
                    "down" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia._15ma
                    }
                    "stop" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia.Regular
                    }
                    "continue" -> 
                    {
                        return this._nextBeatOttavia
                    }
                    else -> { }
                }
            }
            8.0 -> 
            {
                when (type)
                {
                    "up" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia._8vb
                    }
                    "down" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia._8va
                    }
                    "stop" -> 
                    {
                        return com.omnifret.gplayer.model.Ottavia.Regular
                    }
                    "continue" -> 
                    {
                        return this._nextBeatOttavia
                    }
                    else -> { }
                }
            }
            else -> { }
        }
        return null
    }
    
    /**
     */
    private fun _parseMetronome(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, ratioPosition: Double): Unit{
        var unit: com.omnifret.gplayer.model.Duration? = null
        var perMinute: Double = -1.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "beat-unit" -> 
                {
                    unit = this._parseBeatDuration(c)
                }
                "per-minute" -> 
                {
                    perMinute = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                }
                else -> { }
            }
        }
        if (unit != null && perMinute > 0)
        {
            var tempoAutomation: com.omnifret.gplayer.model.Automation = com.omnifret.gplayer.model.Automation()
            tempoAutomation.type = com.omnifret.gplayer.model.AutomationType.Tempo
            tempoAutomation.value = perMinute * (((unit.toDouble())).toDouble() / (4.0).toDouble())
            tempoAutomation.ratioPosition = ratioPosition
            if (!this._hasSameTempo(masterBar, tempoAutomation))
            {
                masterBar.tempoAutomations.push(tempoAutomation)
            }
        }
    }
    
    /**
     */
    private fun _hasSameTempo(masterBar: com.omnifret.gplayer.model.MasterBar, tempoAutomation: com.omnifret.gplayer.model.Automation): Boolean{
        for (existing in masterBar.tempoAutomations)
        {
            if (tempoAutomation.ratioPosition == existing.ratioPosition && tempoAutomation.value == existing.value)
            {
                return true
            }
        }
        return false
    }
    
    /**
     */
    private fun _parsePedal(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.SustainPedalMarker?{
        var marker: com.omnifret.gplayer.model.SustainPedalMarker = com.omnifret.gplayer.model.SustainPedalMarker()
        when (element.getAttribute("type"))
        {
            "start" -> 
            {
                marker.pedalType = com.omnifret.gplayer.model.SustainPedalMarkerType.Down
            }
            "stop" -> 
            {
                marker.pedalType = com.omnifret.gplayer.model.SustainPedalMarkerType.Up
            }
            "continue" -> 
            {
                marker.pedalType = com.omnifret.gplayer.model.SustainPedalMarkerType.Hold
            }
            else -> 
            {
                return null
            }
        }
        return marker
    }
    
    /**
     */
    private fun _parseDynamics(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.DynamicValue?{
        for (c in element.childElements())
        {
            var dynamicString: String = c.localName!!.uppercase().toString()
            when (dynamicString)
            {
                "PPP", "PP", "P", "MP", "MF", "F", "FF", "FFF", "PPPP", "PPPPP", "PPPPPP", "FFFF", "FFFFF", "FFFFFF", "SF", "SFP", "SFPP", "FP", "RF", "RFZ", "SFZ", "SFFZ", "FZ", "N", "PF", "SFZP" -> 
                {
                    return com.omnifret.gplayer.core.TypeHelper.parseEnum<com.omnifret.gplayer.model.DynamicValue>(dynamicString, com.omnifret.gplayer.model.DynamicValue::class)
                }
                else -> { }
            }
        }
        return null
    }
    
    /**
     */
    private fun _parseForward(element: com.omnifret.gplayer.xml.XmlNode): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "duration" -> 
                {
                    this._musicalPosition += this._musicXmlDivisionsToNotationTicks(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText))
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseBackup(element: com.omnifret.gplayer.xml.XmlNode): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "duration" -> 
                {
                    var beat: com.omnifret.gplayer.model.Beat? = this._lastBeat
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat)))
                    {
                        var musicalPosition: Double = this._musicalPosition
                        musicalPosition -= this._musicXmlDivisionsToNotationTicks(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText))
                        if (musicalPosition < 0)
                        {
                            musicalPosition = 0.0
                        }
                        this._musicalPosition = musicalPosition
                    }
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _getOrCreateStaff(track: com.omnifret.gplayer.model.Track, staffIndex: Double): com.omnifret.gplayer.model.Staff{
        while (track.staves.length <= staffIndex)
        {
            var staff: com.omnifret.gplayer.model.Staff = com.omnifret.gplayer.model.Staff()
            track.addStaff(staff)
            if (this._score.masterBars.length > 0)
            {
                this._getOrCreateBar(staff, this._score.masterBars[(this._score.masterBars.length - (1.0).toDouble()).toInt()])
            }
        }
        return track.staves[(staffIndex).toInt()]
    }
    
    /**
     */
    private fun _getOrCreateBar(staff: com.omnifret.gplayer.model.Staff, masterBar: com.omnifret.gplayer.model.MasterBar): com.omnifret.gplayer.model.Bar{
        var voiceCount: Double = if(staff.bars.length == 0.0)  1.0 else staff.bars[(0).toInt()].voices.length
        while (staff.bars.length <= masterBar.index)
        {
            var newBar: com.omnifret.gplayer.model.Bar = com.omnifret.gplayer.model.Bar()
            staff.addBar(newBar)
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(newBar.previousBar)))
            {
                newBar.clef = newBar.previousBar!!.clef
                newBar.clefOttava = newBar.previousBar!!.clefOttava
                newBar.keySignature = newBar.previousBar!!.keySignature
                newBar.keySignatureType = newBar.previousBar!!.keySignatureType
            }
            if (this._keyAllStaves != null)
            {
                newBar.keySignature = this._keyAllStaves!!.v0
                newBar.keySignatureType = this._keyAllStaves!!.v1
            }
            if (true) {
                var i: Double = 0.0
                
                while(i < voiceCount){
                    var voice: com.omnifret.gplayer.model.Voice = com.omnifret.gplayer.model.Voice()
                    newBar.addVoice(voice)
                    i++
                }
            }
        }
        return staff.bars[(masterBar.index).toInt()]
    }
    
    /**
     */
    private fun _getOrCreateVoice(bar: com.omnifret.gplayer.model.Bar, voiceIndex: Double): com.omnifret.gplayer.model.Voice{
        var voicesCreated: Boolean = false
        while (bar.voices.length <= voiceIndex)
        {
            bar.addVoice(com.omnifret.gplayer.model.Voice())
            voicesCreated = true
        }
        if (voicesCreated)
        {
            for (b in bar.staff.bars)
            {
                while (b.voices.length <= voiceIndex)
                {
                    b.addVoice(com.omnifret.gplayer.model.Voice())
                }
            }
        }
        return bar.voices[(voiceIndex).toInt()]
    }
    
    /**
     */
    private fun _parseNote(element: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar, track: com.omnifret.gplayer.model.Track): Unit{
        var beat: com.omnifret.gplayer.model.Beat? = null
        var graceType: com.omnifret.gplayer.model.GraceType = com.omnifret.gplayer.model.GraceType.None
        var graceDurationInDivisions: Double = 0.0
        var beamMode: com.omnifret.gplayer.model.BeatBeamingMode? = null
        var isChord: Boolean = false
        var staffIndex: Double = 0.0
        var voiceIndex: Double = 0.0
        var durationInTicks: Double = -1.0
        var beatDuration: com.omnifret.gplayer.model.Duration? = null
        var dots: Double = 0.0
        var tupletNumerator: Double = -1.0
        var tupletDenominator: Double = -1.0
        var preferredBeamDirection: com.omnifret.gplayer.rendering.utils.BeamDirection? = null
        var note: com.omnifret.gplayer.model.Note? = null
        var isPitched: Boolean = false
        var instrumentId: String? = null
        var noteIsVisible: Boolean = element.getAttribute("print-object", "yes") != "no"
        var ensureBeat: (() -> Unit) = fun(): Unit{
            if (beat != null)
            {
                return
            }
            if (isChord && !com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._lastBeat)))
            {
                com.omnifret.gplayer.Logger.warning("MusicXML", "Malformed MusicXML, <chord /> cannot be set on the first note of a measure")
                isChord = false
            }
            if (isChord && !com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
            {
                com.omnifret.gplayer.Logger.warning("MusicXML", "Cannot mix <chord /> and <rest />")
                isChord = false
            }
            var staff: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, staffIndex)
            if (isChord)
            {
                beat = this._lastBeat!!
                beat!!.addNote(note!!)
                return
            }
            var bar: com.omnifret.gplayer.model.Bar = this._getOrCreateBar(staff, masterBar)
            var voice: com.omnifret.gplayer.model.Voice = this._getOrCreateVoice(bar, voiceIndex)
            var actualMusicalPosition: Double = if(voice.beats.length == 0.0)  0.0 else voice.beats[(voice.beats.length - (1.0).toDouble()).toInt()].displayEnd
            var gap: Double = this._musicalPosition - actualMusicalPosition
            if (gap > 0)
            {
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._lastBeat)) && this._lastBeat!!.beamingMode == com.omnifret.gplayer.model.BeatBeamingMode.ForceMergeWithNext) && this._lastBeat!!.voice.bar.staff.index != staffIndex) && voice.beats.length > 0) && voice.beats[(voice.beats.length - (1.0).toDouble()).toInt()].beamingMode == com.omnifret.gplayer.model.BeatBeamingMode.ForceMergeWithNext))
                {
                    var preferredDuration: com.omnifret.gplayer.model.Duration = voice.beats[(voice.beats.length - (1.0).toDouble()).toInt()].duration
                    while (gap > 0)
                    {
                        var restGap: com.omnifret.gplayer.model.Beat? = this._createRestForGap(gap, preferredDuration)
                        if (restGap != null)
                        {
                            this._insertBeatToVoice(restGap!!, voice)
                            gap -= restGap!!.playbackDuration
                        }
                        else 
                        {
                            break
                        }
                    }
                }
                if (gap > 0)
                {
                    var placeholder: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
                    placeholder.dynamics = this._currentDynamics
                    placeholder.isEmpty = true
                    placeholder.duration = com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth
                    placeholder.overrideDisplayDuration = gap
                    placeholder.updateDurations()
                    this._insertBeatToVoice(placeholder, voice)
                }
            }
            else if (gap < 0)
            {
                com.omnifret.gplayer.Logger.error("MusicXML", "Unsupported forward/backup detected. Cannot fill new beats into already filled area of voice")
            }
            if (durationInTicks < 0 && beatDuration != null)
            {
                durationInTicks = com.omnifret.gplayer.midi.MidiUtils.toTicks(beatDuration!!)
                if (dots > 0)
                {
                    durationInTicks = com.omnifret.gplayer.midi.MidiUtils.applyDot(durationInTicks, dots == 2.0)
                }
            }
            var newBeat: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
            beat = newBeat
            if (beamMode == null)
            {
                newBeat.beamingMode = if(this._getStaffContext(staff).isExplicitlyBeamed)  com.omnifret.gplayer.model.BeatBeamingMode.ForceSplitToNext else com.omnifret.gplayer.model.BeatBeamingMode.Auto
            }
            else 
            {
                newBeat.beamingMode = beamMode!!
                this._getStaffContext(staff).isExplicitlyBeamed = true
            }
            newBeat.isEmpty = false
            newBeat.dynamics = this._currentDynamics
            if (this._isBeatSlash)
            {
                newBeat.slashed = true
            }
            var automations: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Automation>? = this._nextBeatAutomations
            this._nextBeatAutomations = null
            if (automations != null)
            {
                for (automation in automations!!)
                {
                    newBeat.automations.push(automation)
                }
            }
            var chord: com.omnifret.gplayer.model.Chord? = this._nextBeatChord
            this._nextBeatChord = null
            if (chord != null)
            {
                newBeat.chordId = chord!!.uniqueId
                if (!voice.bar.staff.hasChord(chord!!.uniqueId))
                {
                    voice.bar.staff.addChord(newBeat.chordId!!, chord!!)
                }
            }
            var crescendo: com.omnifret.gplayer.model.CrescendoType? = this._nextBeatCrescendo
            if (crescendo != null)
            {
                newBeat.crescendo = crescendo!!
            }
            var ottavia: com.omnifret.gplayer.model.Ottavia? = this._nextBeatOttavia
            if (ottavia != null)
            {
                newBeat.ottava = ottavia!!
            }
            newBeat.isLetRing = this._nextBeatLetRing
            newBeat.isPalmMute = this._nextBeatPalmMute
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(this._nextBeatText)))
            {
                newBeat.text = this._nextBeatText!!
                this._nextBeatText = null
            }
            if (note != null)
            {
                newBeat.addNote(note!!)
            }
            this._insertBeatToVoice(newBeat, voice)
            if (note != null)
            {
                note!!.isVisible = noteIsVisible
                var trackInfo: com.omnifret.gplayer.importer.TrackInfo = this._indexToTrackInfo.get(track.index)!!
                if (instrumentId != null)
                {
                    note!!.percussionArticulation = trackInfo.getOrCreateArticulation(instrumentId!!, note!!)
                }
                else if (!isPitched)
                {
                    note!!.percussionArticulation = trackInfo.getOrCreateArticulation("", note!!)
                }
            }
            if (graceType != com.omnifret.gplayer.model.GraceType.None)
            {
                newBeat.graceType = graceType
                this._applyBeatDurationFromTicks(newBeat, graceDurationInDivisions, null, false)
            }
            else 
            {
                newBeat.tupletNumerator = tupletNumerator
                newBeat.tupletDenominator = tupletDenominator
                newBeat.dots = dots
                newBeat.preferredBeamDirection = preferredBeamDirection
                this._applyBeatDurationFromTicks(newBeat, durationInTicks, beatDuration, true)
            }
            this._musicalPosition = newBeat.displayEnd
            this._lastBeat = newBeat
        }
        
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "grace" -> 
                {
                    var makeTime: Double = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.getAttribute("make-time", "-1"))
                    if (makeTime >= 0)
                    {
                        graceDurationInDivisions = this._musicXmlDivisionsToNotationTicks(makeTime)
                        graceType = com.omnifret.gplayer.model.GraceType.BeforeBeat
                    }
                    else 
                    {
                        graceType = com.omnifret.gplayer.model.GraceType.OnBeat
                    }
                    if (c.getAttribute("slash") == "yes")
                    {
                        graceType = com.omnifret.gplayer.model.GraceType.BeforeBeat
                    }
                }
                "chord" -> 
                {
                    isChord = true
                }
                "cue" -> 
                {
                    return
                }
                "pitch" -> 
                {
                    note = this._parsePitch(c)
                    isPitched = true
                }
                "unpitched" -> 
                {
                    note = this._parseUnpitched(c, track)
                }
                "rest" -> 
                {
                    note = null
                    if (beatDuration == null)
                    {
                        beatDuration = com.omnifret.gplayer.model.Duration.Whole
                    }
                }
                "duration" -> 
                {
                    durationInTicks = this._parseDuration(c)
                }
                "instrument" -> 
                {
                    instrumentId = c.getAttribute("id", "")
                }
                "voice" -> 
                {
                    voiceIndex = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                    if (com.omnifret.gplayer.core.ecmaScript.Number.isNaN(voiceIndex))
                    {
                        com.omnifret.gplayer.Logger.warning("MusicXML", "Voices need to be specified as numbers")
                        voiceIndex = 0.0
                    }
                    else 
                    {
                        voiceIndex = voiceIndex - (1.0).toDouble()
                    }
                }
                "type" -> 
                {
                    beatDuration = this._parseBeatDuration(c)
                }
                "dot" -> 
                {
                    dots++
                }
                "accidental" -> 
                {
                    if (note == null)
                    {
                        com.omnifret.gplayer.Logger.warning("MusicXML", "Malformed MusicXML, missing pitch or unpitched for note")
                    }
                    else 
                    {
                        this._parseAccidental(c, note!!)
                    }
                }
                "time-modification" -> 
                {
                    for (tmc in c.childElements())
                    {
                        when (tmc.localName)
                        {
                            "actual-notes" -> 
                            {
                                tupletNumerator = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(tmc.innerText, 10.0)
                            }
                            "normal-notes" -> 
                            {
                                tupletDenominator = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(tmc.innerText, 10.0)
                            }
                            else -> { }
                        }
                    }
                }
                "stem" -> 
                {
                    preferredBeamDirection = this._parseStem(c)
                }
                "notehead" -> 
                {
                    if (note == null)
                    {
                        com.omnifret.gplayer.Logger.warning("MusicXML", "Malformed MusicXML, missing pitch or unpitched for note")
                    }
                    else 
                    {
                        this._parseNoteHead(c, note!!, beatDuration ?: com.omnifret.gplayer.model.Duration.Quarter, preferredBeamDirection ?: this._estimateBeamDirection(note!!))
                    }
                }
                "staff" -> 
                {
                    staffIndex = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0) - (1.0).toDouble()
                }
                "beam" -> 
                {
                    if (c.getAttribute("number", "1") == "1")
                    {
                        when (c.innerText)
                        {
                            "begin" -> 
                            {
                                beamMode = com.omnifret.gplayer.model.BeatBeamingMode.ForceMergeWithNext
                            }
                            "continue" -> 
                            {
                                beamMode = com.omnifret.gplayer.model.BeatBeamingMode.ForceMergeWithNext
                            }
                            "end" -> 
                            {
                                beamMode = com.omnifret.gplayer.model.BeatBeamingMode.ForceSplitToNext
                            }
                            else -> { }
                        }
                    }
                }
                "notations" -> 
                {
                    ensureBeat()
                    this._parseNotations(c, note, beat!!)
                }
                "lyric" -> 
                {
                    ensureBeat()
                    this._parseLyric(c, beat!!, track)
                }
                "play" -> 
                {
                    this._parsePlay(c, note)
                }
                else -> { }
            }
        }
        if (isPitched)
        {
            var staff: com.omnifret.gplayer.model.Staff = this._getOrCreateStaff(track, staffIndex)
            var transpose: Double = this._getStaffContext(staff).transpose
            if (transpose != 0.0)
            {
                var value: Double = note!!.octave * (12.0).toDouble() + note!!.tone + transpose
                note!!.octave = (((value / (12.0).toDouble())).toInt() or 0).toDouble()
                note!!.tone = value - note!!.octave * (12.0).toDouble()
            }
        }
        ensureBeat()
    }
    
    /**
     */
    private fun _parsePlay(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note?): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "mute" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)) && c.innerText == "palm"))
                    {
                        note!!.isPalmMute = true
                    }
                }
                "semi-pitched" -> 
                {
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _estimateBeamDirection(note: com.omnifret.gplayer.model.Note): com.omnifret.gplayer.rendering.utils.BeamDirection{
        return if(note.calculateRealValue(false, false) < com.omnifret.gplayer.importer.MusicXmlImporter._b4Value)  com.omnifret.gplayer.rendering.utils.BeamDirection.Down else com.omnifret.gplayer.rendering.utils.BeamDirection.Up
    }
    
