    /**
     */
    private fun _createRestForGap(gap: Double, preferredDuration: com.omnifret.gplayer.model.Duration): com.omnifret.gplayer.model.Beat?{
        var parampreferredDuration = preferredDuration
        var preferredDurationTicks: Double = com.omnifret.gplayer.midi.MidiUtils.toTicks(parampreferredDuration)
        while (preferredDurationTicks > gap)
        {
            if (parampreferredDuration == com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth)
            {
                return null
            }
            parampreferredDuration = com.omnifret.gplayer.model.Duration.fromValue(((parampreferredDuration).toDouble() * (2.0).toDouble()))
            preferredDurationTicks = com.omnifret.gplayer.midi.MidiUtils.toTicks(parampreferredDuration)
        }
        var placeholder: com.omnifret.gplayer.model.Beat = com.omnifret.gplayer.model.Beat()
        placeholder.dynamics = this._currentDynamics
        placeholder.isEmpty = false
        placeholder.duration = parampreferredDuration
        placeholder.overrideDisplayDuration = preferredDurationTicks
        placeholder.updateDurations()
        return placeholder
    }
    
    /**
     */
    private fun _insertBeatToVoice(newBeat: com.omnifret.gplayer.model.Beat, voice: com.omnifret.gplayer.model.Voice): Unit{
        if (voice.beats.length > 0)
        {
            var lastBeat: com.omnifret.gplayer.model.Beat = voice.beats[(voice.beats.length - (1.0).toDouble()).toInt()]
            lastBeat.nextBeat = newBeat
            newBeat.previousBeat = lastBeat!!
            var previousNonGraceBeat: com.omnifret.gplayer.model.Beat? = lastBeat
            while (previousNonGraceBeat != null)
            {
                if (previousNonGraceBeat!!.graceType == com.omnifret.gplayer.model.GraceType.None)
                {
                    break
                }
                if (previousNonGraceBeat!!.index > 0)
                {
                    previousNonGraceBeat = previousNonGraceBeat!!.previousBeat
                }
                else 
                {
                    previousNonGraceBeat = null
                }
            }
            if (previousNonGraceBeat != null)
            {
                newBeat.displayStart = previousNonGraceBeat!!.displayEnd
            }
        }
        voice.addBeat(newBeat)
    }
    
    /**
     */
    private fun _musicXmlDivisionsToNotationTicks(divisions: Double): Double{
        return (divisions * com.omnifret.gplayer.midi.MidiUtils.QuarterTime) / this._divisionsPerQuarterNote
    }
    
    /**
     */
    private fun _parseBeatDuration(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.Duration?{
        when (element.innerText)
        {
            "1024th" -> 
            {
                return com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth
            }
            "512th" -> 
            {
                return com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth
            }
            "256th" -> 
            {
                return com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth
            }
            "128th" -> 
            {
                return com.omnifret.gplayer.model.Duration.OneHundredTwentyEighth
            }
            "64th" -> 
            {
                return com.omnifret.gplayer.model.Duration.SixtyFourth
            }
            "32nd" -> 
            {
                return com.omnifret.gplayer.model.Duration.ThirtySecond
            }
            "16th" -> 
            {
                return com.omnifret.gplayer.model.Duration.Sixteenth
            }
            "eighth" -> 
            {
                return com.omnifret.gplayer.model.Duration.Eighth
            }
            "quarter" -> 
            {
                return com.omnifret.gplayer.model.Duration.Quarter
            }
            "half" -> 
            {
                return com.omnifret.gplayer.model.Duration.Half
            }
            "whole" -> 
            {
                return com.omnifret.gplayer.model.Duration.Whole
            }
            "breve" -> 
            {
                return com.omnifret.gplayer.model.Duration.DoubleWhole
            }
            "long" -> 
            {
                return com.omnifret.gplayer.model.Duration.QuadrupleWhole
            }
            else -> { }
        }
        return null
    }
    
    /**
     */
    private fun _applyBeatDurationFromTicks(newBeat: com.omnifret.gplayer.model.Beat, ticks: Double, beatDuration: com.omnifret.gplayer.model.Duration?, applyDisplayDuration: Boolean): Unit{
        var parambeatDuration = beatDuration
        if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(parambeatDuration)))
        {
            if (true) {
                var i: Double = 0.0
                
                while(i < com.omnifret.gplayer.importer.MusicXmlImporter._allDurations.length){
                    var dt: Double = com.omnifret.gplayer.importer.MusicXmlImporter._allDurationTicks[(i).toInt()]
                    if (ticks >= dt)
                    {
                        parambeatDuration = com.omnifret.gplayer.importer.MusicXmlImporter._allDurations[(i).toInt()]
                    }
                    else 
                    {
                        break
                    }
                    i++
                }
            }
        }
        newBeat.duration = parambeatDuration ?: com.omnifret.gplayer.model.Duration.Sixteenth
        if (applyDisplayDuration)
        {
            newBeat.overrideDisplayDuration = ticks
        }
        newBeat.updateDurations()
    }
    
    /**
     */
    private fun _parseLyric(element: com.omnifret.gplayer.xml.XmlNode, beat: com.omnifret.gplayer.model.Beat, track: com.omnifret.gplayer.model.Track): Unit{
        var info: com.omnifret.gplayer.importer.TrackInfo = this._indexToTrackInfo.get(track.index)!!
        var index: Double = info.getLyricLine(element.getAttribute("number", ""))
        if (beat.lyrics == null)
        {
            beat.lyrics = com.omnifret.gplayer.collections.List<String>(
            )
            
        }
        while (beat.lyrics!!.length <= index)
        {
            beat.lyrics!!.push("")
        }
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "text" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat.lyrics!![(index).toInt()])))
                    {
                        beat.lyrics!![(index).toInt()] += """ ${(c.innerText).toTemplate()}"""
                    }
                    else 
                    {
                        beat.lyrics!![(index).toInt()] = c.innerText
                    }
                }
                "elision" -> 
                {
                    beat.lyrics!![(index).toInt()] += c.innerText
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseNotations(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note?, beat: com.omnifret.gplayer.model.Beat): Unit{
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "tied" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        this._parseTied(c, note!!, beat.voice.bar.staff)
