                }
                "glissando" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        this._parseGlissando(c, note!!)
                    }
                }
                "slide" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        this._parseSlide(c, note!!)
                    }
                }
                "ornaments" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        this._parseOrnaments(c, note!!)
                    }
                }
                "technical" -> 
                {
                    this._parseTechnical(c, note, beat)
                }
                "articulations" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
