                "dynamics" -> 
                {
                    var dynamics: com.omnifret.gplayer.model.DynamicValue? = this._parseDynamics(c)
                    if (dynamics != null)
                    {
                        beat.dynamics = ((dynamics as com.omnifret.gplayer.model.DynamicValue))
                        this._currentDynamics = ((dynamics as com.omnifret.gplayer.model.DynamicValue))
                    }
                }
                "fermata" -> 
                {
                    this._parseFermata(c, beat)
                }
                "arpeggiate" -> 
                {
                    this._parseArpeggiate(c, beat)
                }
