    /**
     */
    private fun _parseTechnical(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note?, beat: com.omnifret.gplayer.model.Beat): Unit{
        var bends: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode>(
        )
        
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "up-bow" -> 
                {
                    beat.pickStroke = com.omnifret.gplayer.model.PickStroke.Up
                }
                "down-bow" -> 
                {
                    beat.pickStroke = com.omnifret.gplayer.model.PickStroke.Down
                }
                "harmonic" -> 
                {
                }
                "fingering" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.leftHandFinger = this._parseFingering(c)
                    }
                }
                "pluck" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.rightHandFinger = this._parseFingering(c)
                    }
                }
                "fret" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.fret = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                    }
                }
                "string" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.string = beat.voice.bar.staff.tuning.length - com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0) + 1.0
                    }
                }
                "hammer-on", "pull-off" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.isHammerPullOrigin = true
                    }
                }
                "bend" -> 
                {
                    bends.push(c)
                }
                "tap" -> 
                {
                    beat.tap = true
                }
                "smear" -> 
                {
                    if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)))
                    {
                        note!!.vibrato = com.omnifret.gplayer.model.VibratoType.Slight
                    }
                }
                "golpe" -> 
                {
                    when (c.getAttribute("placement", "above"))
                    {
                        "above" -> 
                        {
                            beat.golpe = com.omnifret.gplayer.model.GolpeType.Finger
                        }
                        "below" -> 
                        {
                            beat.golpe = com.omnifret.gplayer.model.GolpeType.Thumb
                        }
                        else -> { }
                    }
                }
                else -> { }
            }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(note)) && bends.length > 0))
        {
            this._parseBends(bends, note!!)
        }
    }
    
    /**
     */
    private fun _parseBends(elements: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.xml.XmlNode>, note: com.omnifret.gplayer.model.Note): Unit{
        var baseOffset: Double = com.omnifret.gplayer.model.BendPoint.MaxPosition / elements.length
        var currentValue: Double = 0.0
        var currentOffset: Double = 0.0
        var isFirstBend: Boolean = true
        for (bend in elements)
        {
            var bendAlterElement: com.omnifret.gplayer.xml.XmlNode? = bend.findChildElement("bend-alter")
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bendAlterElement)))
            {
                var absValue: Double = com.omnifret.gplayer.core.ecmaScript.Math.round(com.omnifret.gplayer.core.ecmaScript.Math.abs(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(bendAlterElement!!.innerText)) * (2.0).toDouble())
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bend.findChildElement("pre-bend"))))
                {
                    if (isFirstBend)
                    {
                        currentValue += absValue
                        note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                        currentOffset += baseOffset
                        note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                        isFirstBend = false
                    }
                    else 
                    {
                        currentOffset += baseOffset
                    }
                }
                else if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bend.findChildElement("release"))))
                {
                    if (isFirstBend)
                    {
                        currentValue += absValue
                    }
                    note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                    currentOffset += baseOffset
                    currentValue -= absValue
                    note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                    isFirstBend = false
                }
                else 
                {
                    note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                    currentValue += absValue
                    currentOffset += baseOffset
                    note.addBendPoint(com.omnifret.gplayer.model.BendPoint(currentOffset, currentValue))
                    isFirstBend = false
                }
            }
        }
    }
    
