    private var _currentTrillStep: Double = -1.0
    
    /**
     */
    private fun _parseOrnaments(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note): Unit{
        var currentTrillStep: Double = -1.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "trill-mark" -> 
                {
                    currentTrillStep = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.getAttribute("trill-step", "2"), 10.0)
                    if (note.isStringed)
                    {
                        note.trillValue = note.stringTuning + currentTrillStep
                    }
                    else if (!note.isPercussion)
                    {
                        note.trillValue = note.calculateRealValue(false, false) + currentTrillStep
                    }
                }
                "turn" -> 
                {
                    note.ornament = com.omnifret.gplayer.model.NoteOrnament.Turn
                }
                "inverted-turn" -> 
                {
                    note.ornament = com.omnifret.gplayer.model.NoteOrnament.InvertedTurn
                }
                "wavy-line" -> 
                {
                    if (currentTrillStep > 0)
                    {
                        if (c.getAttribute("type") == "start")
                        {
                            this._currentTrillStep = currentTrillStep
                        }
                    }
                    else if (this._currentTrillStep > 0)
                    {
                        if (c.getAttribute("type") == "stop")
                        {
                            this._currentTrillStep = -1.0
                        }
                        else if (note.isStringed)
                        {
                            note.trillValue = note.stringTuning + this._currentTrillStep
                        }
                        else if (!note.isPercussion)
                        {
                            note.trillValue = note.calculateRealValue(false, false) + this._currentTrillStep
                        }
                    }
                    else 
                    {
                        note.vibrato = com.omnifret.gplayer.model.VibratoType.Slight
                    }
                }
                "mordent" -> 
                {
                    note.ornament = com.omnifret.gplayer.model.NoteOrnament.LowerMordent
                }
                "inverted-mordent" -> 
                {
                    note.ornament = com.omnifret.gplayer.model.NoteOrnament.UpperMordent
                }
                "tremolo" -> 
                {
                    var tremolo: com.omnifret.gplayer.model.TremoloPickingEffect = com.omnifret.gplayer.model.TremoloPickingEffect()
                    note.beat.tremoloPicking = tremolo
                    tremolo.marks = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0)
                    if ((c.getAttribute("type", "") == "unmeasured" && tremolo.marks == 0.0) || c.getAttribute("smufl", "") == "buzzRoll")
                    {
                        tremolo.style = com.omnifret.gplayer.model.TremoloPickingStyle.BuzzRoll
                    }
                }
                else -> { }
            }
        }
    }
    
    /**
     */
    private fun _parseSlide(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note): Unit{
        var type: String = element.getAttribute("type")
        var number: String = element.getAttribute("number", "1")
        var context: com.omnifret.gplayer.importer.StaffContext = this._getStaffContext(note.beat.voice.bar.staff)
        when (type)
        {
            "start" -> 
            {
                context.slideOrigins.set(number, note)
            }
            "stop" -> 
            {
                if (context.slideOrigins.has(number))
                {
                    var origin: com.omnifret.gplayer.model.Note = context.slideOrigins.get(number)!!
                    origin.slideTarget = note
                    note.slideOrigin = origin
                    origin.slideOutType = com.omnifret.gplayer.model.SlideOutType.Shift
                }
            }
