    }
    
    /**
     */
    private fun _parseTied(element: com.omnifret.gplayer.xml.XmlNode, note: com.omnifret.gplayer.model.Note, staff: com.omnifret.gplayer.model.Staff): Unit{
        var type: String = element.getAttribute("type")
        var number: String = element.getAttribute("number", "")
        var context: com.omnifret.gplayer.importer.StaffContext = this._getStaffContext(staff)
        if (type == "start")
        {
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(number)))
            {
                if (context.tieStartIds.has(number))
                {
                    var unclosed: com.omnifret.gplayer.model.Note = context.tieStartIds.get(number)!!
                    context.tieStarts.delete(unclosed)
                }
                context.tieStartIds.set(number, note)
            }
            context.tieStarts.add(note)
        }
        else if (type == "stop" && !note.isTieDestination)
        {
            var tieOrigin: com.omnifret.gplayer.model.Note? = null
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(number)))
            {
                if (!context.tieStartIds.has(number))
                {
                    return
                }
                tieOrigin = context.tieStartIds.get(number)!!
                context.tieStartIds.delete(number)
                context.tieStarts.delete(note)
            }
            else 
            {
                var realValue: Double = this._calculatePitchedNoteValue(note)
                for (t in context.tieStarts)
                {
                    if (this._calculatePitchedNoteValue(t) == realValue)
                    {
                        tieOrigin = t
                        context.tieStarts.delete(tieOrigin!!)
                        break
                    }
                }
            }
            if (!com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(tieOrigin)))
            {
                return
            }
            note.isTieDestination = true
            note.tieOrigin = tieOrigin!!
        }
    }
    
