    /**
     */
    private fun _calculatePitchedNoteValue(note: com.omnifret.gplayer.model.Note): Double{
        return note.octave * (12.0).toDouble() + note.tone
    }
    
    /**
     */
    private fun _parseDuration(element: com.omnifret.gplayer.xml.XmlNode): Double{
        return this._musicXmlDivisionsToNotationTicks(com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(element.innerText))
    }
    
    /**
     */
    private fun _parseUnpitched(element: com.omnifret.gplayer.xml.XmlNode, _track: com.omnifret.gplayer.model.Track): com.omnifret.gplayer.model.Note{
        var step: String = ""
        var octave: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "display-step" -> 
                {
                    step = c.innerText
                }
                "display-octave" -> 
                {
                    octave = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0) + 1.0
                }
                else -> { }
            }
        }
        var note: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.model.Note()
        if (step == "")
        {
            note.octave = 0.0
            note.tone = 0.0
        }
        else 
        {
            var value: Double = octave * (12.0).toDouble() + (com.omnifret.gplayer.model.ModelUtils.getToneForText(step)?.noteValue ?: 0.0)
            note.octave = (((value / (12.0).toDouble())).toInt() or 0).toDouble()
            note.tone = value - note.octave * (12.0).toDouble()
        }
        return note
    }
    
    /**
     */
    private fun _parsePitch(element: com.omnifret.gplayer.xml.XmlNode): com.omnifret.gplayer.model.Note{
        var step: String = ""
        var semitones: Double = 0.0
        var octave: Double = 0.0
        for (c in element.childElements())
        {
            when (c.localName)
            {
                "step" -> 
                {
                    step = c.innerText
                }
                "alter" -> 
                {
                    semitones = com.omnifret.gplayer.core.ecmaScript.Number.parseFloat(c.innerText)
                    if (com.omnifret.gplayer.core.ecmaScript.Number.isNaN(semitones))
                    {
                        semitones = 0.0
                    }
                }
                "octave" -> 
                {
                    octave = com.omnifret.gplayer.core.ecmaScript.Number.parseInt(c.innerText, 10.0) + 1.0
                }
                else -> { }
            }
        }
        semitones = ((semitones).toInt() or 0).toDouble()
        var value: Double = octave * (12.0).toDouble() + (com.omnifret.gplayer.model.ModelUtils.getToneForText(step)?.noteValue ?: 0.0) + semitones
        var note: com.omnifret.gplayer.model.Note = com.omnifret.gplayer.model.Note()
        note.octave = (((value / (12.0).toDouble())).toInt() or 0).toDouble()
        note.tone = value - note.octave * (12.0).toDouble()
        return note
    }
    
    /**
     */
    private fun _applyNoteHead(note: com.omnifret.gplayer.model.Note, 
    beatDuration: com.omnifret.gplayer.model.Duration, 
    forceFill: Boolean?, 
    doubleWhole: com.omnifret.gplayer.model.MusicFontSymbol, 
    whole: com.omnifret.gplayer.model.MusicFontSymbol, 
    half: com.omnifret.gplayer.model.MusicFontSymbol, 
    filled: com.omnifret.gplayer.model.MusicFontSymbol): Unit{
        if (forceFill == null)
        {
            when (beatDuration)
            {
                com.omnifret.gplayer.model.Duration.QuadrupleWhole, com.omnifret.gplayer.model.Duration.DoubleWhole -> 
                {
                    note.style!!.noteHead = doubleWhole
                }
                com.omnifret.gplayer.model.Duration.Whole -> 
                {
                    note.style!!.noteHead = whole
                }
                com.omnifret.gplayer.model.Duration.Half -> 
                {
                    note.style!!.noteHead = half
                }
                else -> 
                {
                    note.style!!.noteHead = filled
                }
            }
        }
        else if (forceFill!! == true)
        {
            note.style!!.noteHead = filled
        }
        else 
        {
            when (beatDuration)
            {
                com.omnifret.gplayer.model.Duration.QuadrupleWhole, com.omnifret.gplayer.model.Duration.DoubleWhole -> 
                {
                    note.style!!.noteHead = doubleWhole
                }
                com.omnifret.gplayer.model.Duration.Whole -> 
                {
                    note.style!!.noteHead = whole
                }
                com.omnifret.gplayer.model.Duration.Half -> 
                {
                    note.style!!.noteHead = half
                }
                else -> 
                {
                    note.style!!.noteHead = half
                }
            }
        }
    }
    
    companion object{
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _sanitizeDisplay(text: String): String{
            return text.replaceAll("\r", "").replaceAll("\n", " ").replaceAll("\t", "  ").replaceAll(" ", " ")
        }
        
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _interpolatePercent(value: Double): Double{
            return ((com.omnifret.gplayer.importer.MusicXmlImporter._interpolate(0.0, 100.0, 0.0, 16.0, value)).toInt() or 0).toDouble()
        }
        
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _interpolatePan(value: Double): Double{
            return ((com.omnifret.gplayer.importer.MusicXmlImporter._interpolate(-90.0, 90.0, 0.0, 16.0, value)).toInt() or 0).toDouble()
        }
        
        /**
         */
        @kotlin.jvm.JvmStatic
        private fun _interpolate(inputStart: Double, inputEnd: Double, outputStart: Double, outputEnd: Double, value: Double): Double{
            var t: Double = (value - inputStart) / (inputEnd - inputStart)
            return outputStart + (outputEnd - outputStart) * t
        }
        
        @kotlin.jvm.JvmStatic
        private val _b4Value: Double = 71.0
        
        @kotlin.jvm.JvmStatic
        private var _allDurations: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Duration> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Duration>(
            
            com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth, 
            
            com.omnifret.gplayer.model.Duration.OneHundredTwentyEighth, 
            
            com.omnifret.gplayer.model.Duration.SixtyFourth, 
            
            com.omnifret.gplayer.model.Duration.ThirtySecond, 
            
            com.omnifret.gplayer.model.Duration.Sixteenth, 
            
            com.omnifret.gplayer.model.Duration.Eighth, 
            
            com.omnifret.gplayer.model.Duration.Quarter, 
            
            com.omnifret.gplayer.model.Duration.Half, 
            
            com.omnifret.gplayer.model.Duration.Whole, 
            
            com.omnifret.gplayer.model.Duration.DoubleWhole, 
            
            com.omnifret.gplayer.model.Duration.QuadrupleWhole)
        
        
        @kotlin.jvm.JvmStatic
        private var _allDurationTicks: com.omnifret.gplayer.collections.DoubleList = com.omnifret.gplayer.importer.MusicXmlImporter._allDurations.map(fun(d: com.omnifret.gplayer.model.Duration): Double{
            return com.omnifret.gplayer.midi.MidiUtils.toTicks(d)
        }
        )
        
    }
    public constructor()
    : super()
}

