@kotlin.contracts.ExperimentalContracts
@kotlin.ExperimentalUnsignedTypes
internal class TrackInfo
{
    public var track: com.omnifret.gplayer.model.Track
    
    public var firstArticulation: com.omnifret.gplayer.importer.InstrumentArticulationWithPlaybackInfo? = null
    
    public var instruments: com.omnifret.gplayer.collections.Map<String, com.omnifret.gplayer.importer.InstrumentArticulationWithPlaybackInfo> = com.omnifret.gplayer.collections.Map<String, com.omnifret.gplayer.importer.InstrumentArticulationWithPlaybackInfo>()
    
    
    private var _instrumentIdToArticulationIndex: com.omnifret.gplayer.collections.ObjectDoubleMap<String> = com.omnifret.gplayer.collections.ObjectDoubleMap<String>()
    
    private var _lyricsLine: Double = 0.0
    
    private var _lyricsLines: com.omnifret.gplayer.collections.ObjectDoubleMap<String> = com.omnifret.gplayer.collections.ObjectDoubleMap<String>()
    
    public constructor(track: com.omnifret.gplayer.model.Track){
        this.track = track
    }
    
    /**
     */
    public fun getLyricLine(number: String): Double{
        if (this._lyricsLines.has(number))
        {
            return this._lyricsLines.get(number)!!
        }
        var line: Double = this._lyricsLine
        this._lyricsLines.set(number, line)
        this._lyricsLine++
        return line
    }
    
    /**
     */
    public fun getOrCreateArticulation(instrumentId: String, note: com.omnifret.gplayer.model.Note): Double{
        var noteValue: Double = note.octave * (12.0).toDouble() + note.tone
        var lookup: String = """${(instrumentId).toTemplate()}_${(noteValue).toTemplate()}"""
        if (this._instrumentIdToArticulationIndex.has(lookup))
        {
            return this._instrumentIdToArticulationIndex.get(lookup)!!
        }
        var articulation: com.omnifret.gplayer.model.InstrumentArticulation
        if (this.instruments.has(instrumentId))
        {
            articulation = this.instruments.get(instrumentId)!!
        }
        else 
        {
            articulation = com.omnifret.gplayer.importer.TrackInfo._defaultNoteArticulation
        }
        var index: Double = this.track.percussionArticulations.length
        var bar: com.omnifret.gplayer.model.Bar = note.beat.voice.bar
        var musicXmlStaffSteps: Double
        if (noteValue == 0.0)
        {
            musicXmlStaffSteps = 4.0
        }
        else 
        {
            var spelling: com.omnifret.gplayer.model.ResolvedSpelling = com.omnifret.gplayer.model.ModelUtils.resolveSpelling(bar.keySignature, noteValue, com.omnifret.gplayer.model.NoteAccidentalMode.Default)
            musicXmlStaffSteps = com.omnifret.gplayer.rendering.utils.AccidentalHelper.calculateNoteSteps(bar.clef, spelling)
        }
        var actualSteps: Double = note.beat.voice.bar.staff.standardNotationLineCount * (2.0).toDouble() - (1.0).toDouble()
        var fiveLineSteps: Double = (5.0).toDouble() * (2.0).toDouble() - (1.0).toDouble()
        var stepDifference: Double = fiveLineSteps - actualSteps
        var staffLine: Double = musicXmlStaffSteps - stepDifference
        var newArticulation: com.omnifret.gplayer.model.InstrumentArticulation = com.omnifret.gplayer.model.InstrumentArticulation.create(
            articulation.id
            , 
            articulation.elementType
            , 
            staffLine
            , 
            articulation.outputMidiNumber
            , 
            articulation.noteHeadDefault
            , 
            articulation.noteHeadHalf
            , 
            articulation.noteHeadWhole
            , 
            articulation.techniqueSymbol
            , 
            articulation.techniqueSymbolPlacement
        
        )
        this._instrumentIdToArticulationIndex.set(lookup, index)
        this.track.percussionArticulations.push(newArticulation)
        return index
    }
    
    companion object{
        @kotlin.jvm.JvmStatic
        private var _defaultNoteArticulation: com.omnifret.gplayer.model.InstrumentArticulation = com.omnifret.gplayer.model.InstrumentArticulation.create(
            0.0
            , 
            "Default"
            , 
            0.0
            , 
            0.0
            , 
            com.omnifret.gplayer.model.MusicFontSymbol.NoteheadBlack
            , 
            com.omnifret.gplayer.model.MusicFontSymbol.NoteheadHalf
            , 
            com.omnifret.gplayer.model.MusicFontSymbol.NoteheadWhole
        
        )
        
    }
}

